  1→import React, { useState } from 'react';
  2→import { User } from '../types';
  3→import { simulateCitation, CitationSimulationResult, AIEngineResponse } from '../services/ai-citation-simulator';
  4→import {
  5→  ArrowLeft, Search, Loader2, Sparkles, Zap, Eye, MessageSquare,
  6→  ThumbsUp, ThumbsDown, Minus, CheckCircle, XCircle, AlertTriangle,
  7→  Lightbulb, Users, BarChart3, Globe,
  8→} from 'lucide-react';
  9→
 10→interface Props {
 11→  onBack: () => void;
 12→  user: User | null;
 13→  onDeductCredits: (amount: number) => boolean;
 14→}
 15→
 16→const CREDIT_COST = 6;
 17→
 18→const ENGINE_STYLES: Record<string, { color: string; bg: string; gradient: string }> = {
 19→  ChatGPT: { color: 'text-emerald-400', bg: 'bg-emerald-500/10', gradient: 'from-emerald-500/20 to-emerald-600/5' },
 20→  Claude: { color: 'text-orange-400', bg: 'bg-orange-500/10', gradient: 'from-orange-500/20 to-orange-600/5' },
 21→  Perplexity: { color: 'text-blue-400', bg: 'bg-blue-500/10', gradient: 'from-blue-500/20 to-blue-600/5' },
 22→  Gemini: { color: 'text-purple-400', bg: 'bg-purple-500/10', gradient: 'from-purple-500/20 to-purple-600/5' },
 23→  'AI Overviews': { color: 'text-rose-400', bg: 'bg-rose-500/10', gradient: 'from-rose-500/20 to-rose-600/5' },
 24→};
 25→
 26→const MentionBadge: React.FC<{ type: AIEngineResponse['mentionType'] }> = ({ type }) => {
 27→  const styles = {
 28→    direct: { label: 'Mention directe', color: 'text-emerald-400', bg: 'bg-emerald-500/10', icon: CheckCircle },
 29→    indirect: { label: 'Mention indirecte', color: 'text-amber-400', bg: 'bg-amber-500/10', icon: AlertTriangle },
 30→    comparison: { label: 'En comparaison', color: 'text-blue-400', bg: 'bg-blue-500/10', icon: Users },
 31→    absent: { label: 'Non mentionné', color: 'text-red-400', bg: 'bg-red-500/10', icon: XCircle },
 32→  };
 33→  const s = styles[type];
 34→  const Icon = s.icon;
 35→  return (
 36→    <span className={`inline-flex items-center gap-1 text-[10px] font-semibold px-2 py-0.5 rounded-full ${s.bg} ${s.color}`}>
 37→      <Icon size={10} /> {s.label}
 38→    </span>
 39→  );
 40→};
 41→
 42→const SentimentIcon: React.FC<{ sentiment: AIEngineResponse['sentiment'] }> = ({ sentiment }) => {
 43→  if (sentiment === 'positive') return <ThumbsUp size={12} className="text-emerald-400" />;
 44→  if (sentiment === 'negative') return <ThumbsDown size={12} className="text-red-400" />;
 45→  return <Minus size={12} className="text-gray-500" />;
 46→};
 47→
 48→const EngineCard: React.FC<{ engine: AIEngineResponse; brandName: string }> = ({ engine, brandName }) => {
 49→  const style = ENGINE_STYLES[engine.engine] || ENGINE_STYLES.ChatGPT;
 50→  const [expanded, setExpanded] = useState(true);
 51→
 52→  // Highlight brand mentions in the response
 53→  const highlightBrand = (text: string) => {
 54→    if (!brandName) return text;
 55→    const regex = new RegExp(`(${brandName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')})`, 'gi');
 56→    const parts = text.split(regex);
 57→    return parts.map((part, i) =>
 58→      regex.test(part) ? <mark key={i} className="bg-purple-500/30 text-purple-200 rounded px-0.5">{part}</mark> : part
 59→    );
 60→  };
 61→
 62→  return (
 63→    <div className="ninja-card overflow-hidden">
 64→      <div className={`bg-gradient-to-r ${style.gradient} px-4 py-3 flex items-center gap-3 border-b border-white/[0.04]`}>
 65→        <div className={`w-8 h-8 rounded-lg ${style.bg} flex items-center justify-center`}>
 66→          <MessageSquare size={14} className={style.color} />
 67→        </div>
 68→        <div className="flex-1">
 69→          <div className="flex items-center gap-2">
 70→            <span className={`text-sm font-bold ${style.color}`}>{engine.engine}</span>
 71→            <MentionBadge type={engine.mentionType} />
 72→          </div>
 73→        </div>
 74→        <div className="flex items-center gap-3">
 75→          <div className="flex items-center gap-1">
 76→            <SentimentIcon sentiment={engine.sentiment} />
 77→            <span className="text-xs text-gray-500">{engine.sentiment}</span>
 78→          </div>
 79→          <div className="text-right">
 80→            <span className={`text-lg font-bold ${engine.mentionScore >= 60 ? 'text-emerald-400' : engine.mentionScore >= 30 ? 'text-amber-400' : 'text-red-400'}`}>
 81→              {engine.mentionScore}
 82→            </span>
 83→            <span className="text-[10px] text-gray-500">/100</span>
 84→          </div>
 85→        </div>
 86→      </div>
 87→      <div className="p-4">
 88→        <div className="bg-white/[0.02] rounded-xl p-4 border border-white/[0.04]">
 89→          <p className="text-sm text-gray-300 leading-relaxed italic">"{highlightBrand(engine.response)}"</p>
 90→        </div>
 91→        {engine.excerpt && engine.mentionType !== 'absent' && (
 92→          <div className="mt-3 flex items-start gap-2">
 93→            <Eye size={12} className="text-purple-400 mt-0.5 shrink-0" />
 94→            <p className="text-xs text-gray-500">Extrait : <span className="text-purple-300">"{engine.excerpt}"</span></p>
 95→          </div>
 96→        )}
 97→      </div>
 98→    </div>
 99→  );
100→};
101→
102→const AiCitationSimulator: React.FC<Props> = ({ onBack, user, onDeductCredits }) => {
103→  const [query, setQuery] = useState('');
104→  const [brandName, setBrandName] = useState('');
105→  const [brandUrl, setBrandUrl] = useState('');
106→  const [industry, setIndustry] = useState('');
107→  const [isSimulating, setIsSimulating] = useState(false);
108→  const [result, setResult] = useState<CitationSimulationResult | null>(null);
109→
110→  const handleSimulate = async () => {
111→    if (!query || !brandName || !brandUrl) return;
112→    const canProceed = onDeductCredits(CREDIT_COST);
113→    if (!canProceed) return;
114→
115→    setIsSimulating(true);
116→    setResult(null);
117→    try {
118→      const output = await simulateCitation(query, brandName, brandUrl, industry || undefined);
119→      setResult(output);
120→    } catch (err) {
121→      console.error('Simulation failed:', err);
122→    } finally {
123→      setIsSimulating(false);
124→    }
125→  };
126→
127→  const directMentions = result?.engines.filter(e => e.mentionType === 'direct').length || 0;
128→  const avgScore = result ? Math.round(result.engines.reduce((sum, e) => sum + e.mentionScore, 0) / result.engines.length) : 0;
129→
130→  return (
131→    <div className="w-full px-6 py-8 animate-in fade-in duration-500">
132→      {/* Header */}
133→      <div className="flex items-center gap-4 mb-8">
134→        <button onClick={onBack} className="p-2 rounded-xl hover:bg-white/[0.04] transition-colors">
135→          <ArrowLeft size={20} className="text-gray-400" />
136→        </button>
137→        <div className="flex-1">
138→          <div className="flex items-center gap-3">
139→            <h1 className="text-2xl font-bold text-white">Simulateur de <span className="gradient-text">Citation IA</span></h1>
140→            <span className="bg-blue-500/10 text-blue-400 text-xs font-bold px-2.5 py-1 rounded-full border border-blue-500/20 flex items-center gap-1">
141→              <Sparkles size={10} /> NOUVEAU
142→            </span>
143→          </div>
144→          <p className="text-sm text-gray-500 mt-1">Simulez comment ChatGPT, Claude, Perplexity, Gemini et AI Overviews parlent de votre marque</p>
145→        </div>
146→      </div>
147→
148→      {/* Input Form */}
149→      <div className="ninja-card p-6 mb-8">
150→        <div className="space-y-4">
151→          <div>
152→            <label className="block text-sm font-medium text-gray-300 mb-1.5">Question à simuler <span className="text-red-400">*</span></label>
153→            <div className="relative">
154→              <Search size={16} className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500" />
155→              <input value={query} onChange={e => setQuery(e.target.value)}
156→                placeholder="Quel est le meilleur outil pour optimiser sa visibilité IA ?"
157→                className="w-full bg-[#111111] border border-white/[0.08] rounded-xl pl-11 pr-4 py-3 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 transition-colors"
158→                onKeyDown={e => e.key === 'Enter' && handleSimulate()} />
159→            </div>
160→          </div>
161→          <div className="grid md:grid-cols-3 gap-4">
162→            <div>
163→              <label className="block text-sm font-medium text-gray-300 mb-1.5">Votre marque <span className="text-red-400">*</span></label>
164→              <input value={brandName} onChange={e => setBrandName(e.target.value)} placeholder="CitedBy.ai"
165→                className="w-full bg-[#111111] border border-white/[0.08] rounded-xl px-4 py-2.5 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 transition-colors" />
166→            </div>
167→            <div>
168→              <label className="block text-sm font-medium text-gray-300 mb-1.5">URL de la marque <span className="text-red-400">*</span></label>
169→              <input value={brandUrl} onChange={e => setBrandUrl(e.target.value)} placeholder="https://citedby.ai"
170→                className="w-full bg-[#111111] border border-white/[0.08] rounded-xl px-4 py-2.5 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 transition-colors" />
171→            </div>
172→            <div>
173→              <label className="block text-sm font-medium text-gray-300 mb-1.5">Secteur d'activité</label>
174→              <input value={industry} onChange={e => setIndustry(e.target.value)} placeholder="SaaS, Marketing digital..."
175→                className="w-full bg-[#111111] border border-white/[0.08] rounded-xl px-4 py-2.5 text-sm text-gray-200 focus:outline-none focus:border-purple-500/50 transition-colors" />
176→            </div>
177→          </div>
178→          <button onClick={handleSimulate} disabled={isSimulating || !query || !brandName || !brandUrl}
179→            className={`w-full md:w-auto px-8 py-3 rounded-xl font-semibold text-sm flex items-center justify-center gap-2 transition-all ${
180→              isSimulating || !query || !brandName || !brandUrl ? 'bg-gray-700/50 text-gray-500 cursor-not-allowed' : 'btn-gradient text-white'
181→            }`}>
182→            {isSimulating ? (<><Loader2 size={16} className="animate-spin" /> Simulation en cours...</>) : (<><Zap size={16} /> Simuler ({CREDIT_COST} Gas)</>)}
183→          </button>
184→        </div>
185→      </div>
186→
187→      {/* Loading State */}
188→      {isSimulating && (
189→        <div className="ninja-card p-12 flex flex-col items-center justify-center text-center mb-8">
190→          <div className="flex items-center gap-4 mb-6">
191→            {['ChatGPT', 'Claude', 'Perplexity', 'Gemini', 'AI Overviews'].map((name, i) => {
192→              const style = ENGINE_STYLES[name];
193→              return (
194→                <div key={name} className={`w-12 h-12 rounded-xl ${style.bg} flex items-center justify-center`}
195→                  style={{ animation: `pulse 1.5s ease-in-out ${i * 0.3}s infinite` }}>
196→                  <MessageSquare size={20} className={style.color} />
197→                </div>
198→              );
199→            })}
200→          </div>
201→          <h3 className="text-lg font-bold text-gray-300 mb-2">Interrogation des IA en cours...</h3>
202→          <p className="text-sm text-gray-500">Simulation des réponses de 5 moteurs de réponse IA</p>
203→        </div>
204→      )}
205→
206→      {/* Results */}
207→      {result && !isSimulating && (
208→        <div className="space-y-6 animate-in fade-in duration-500">
209→          {/* Score Overview */}
210→          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
211→            <div className="ninja-card p-4 text-center">
212→              <p className={`text-3xl font-bold ${result.overallScore >= 60 ? 'text-emerald-400' : result.overallScore >= 30 ? 'text-amber-400' : 'text-red-400'}`}>
213→                {result.overallScore}
214→              </p>
215→              <p className="text-xs text-gray-500 mt-1">Score global</p>
216→            </div>
217→            <div className="ninja-card p-4 text-center">
218→              <p className="text-3xl font-bold text-purple-400">{directMentions}</p>
219→              <p className="text-xs text-gray-500 mt-1">Mentions directes</p>
220→            </div>
221→            <div className="ninja-card p-4 text-center">
222→              <p className="text-3xl font-bold text-blue-400">{result.engines.filter(e => e.citationPresent).length}</p>
223→              <p className="text-xs text-gray-500 mt-1">Citations avec lien</p>
224→            </div>
225→            <div className="ninja-card p-4 text-center">
226→              <p className="text-3xl font-bold text-amber-400">{result.competitorsMentioned.length}</p>
227→              <p className="text-xs text-gray-500 mt-1">Concurrents cités</p>
228→            </div>
229→          </div>
230→
231→          {/* Query reminder */}
232→          <div className="ninja-card p-4 flex items-center gap-3 border-l-2 border-purple-500/50">
233→            <Search size={16} className="text-purple-400 shrink-0" />
234→            <div>
235→              <p className="text-xs text-gray-500">Question simulée :</p>
236→              <p className="text-sm text-gray-300 font-medium">"{result.query}"</p>
237→            </div>
238→          </div>
239→
240→          {/* Engine Responses */}
241→          <div>
242→            <h3 className="text-sm font-semibold text-gray-400 uppercase tracking-wider mb-4">Réponses simulées par moteur</h3>
243→            <div className="grid md:grid-cols-2 gap-4">
244→              {result.engines.map((engine, i) => (
245→                <EngineCard key={i} engine={engine} brandName={result.brandName} />
246→              ))}
247→            </div>
248→          </div>
249→
250→          {/* Competitors & Improvements */}
251→          <div className="grid md:grid-cols-2 gap-6">
252→            {result.competitorsMentioned.length > 0 && (
253→              <div className="ninja-card p-6">
254→                <h3 className="text-sm font-semibold text-gray-300 mb-3 flex items-center gap-2">
255→                  <Users size={14} className="text-red-400" /> Concurrents mentionnés
256→                </h3>
257→                <div className="flex flex-wrap gap-2">
258→                  {result.competitorsMentioned.map((comp, i) => (
259→                    <span key={i} className="px-3 py-1.5 bg-red-500/5 border border-red-500/10 rounded-lg text-xs text-red-300 font-medium">
260→                      {comp}
261→                    </span>
262→                  ))}
263→                </div>
264→              </div>
265→            )}
266→            <div className="ninja-card p-6">
267→              <h3 className="text-sm font-semibold text-gray-300 mb-3 flex items-center gap-2">
268→                <Lightbulb size={14} className="text-amber-400" /> Comment améliorer votre visibilité
269→              </h3>
270→              <ul className="space-y-2">
271→                {result.improvements.map((imp, i) => (
272→                  <li key={i} className="flex items-start gap-2 text-sm text-gray-400">
273→                    <span className="text-purple-400 mt-0.5 shrink-0">→</span>
274→                    {imp}
275→                  </li>
276→                ))}
277→              </ul>
278→            </div>
279→          </div>
280→        </div>
281→      )}
282→
283→      {/* Empty State */}
284→      {!result && !isSimulating && (
285→        <div className="ninja-card p-12 flex flex-col items-center justify-center text-center">
286→          <div className="flex items-center gap-3 mb-6">
287→            {Object.entries(ENGINE_STYLES).map(([name, style]) => (
288→              <div key={name} className={`w-14 h-14 rounded-xl ${style.bg} flex flex-col items-center justify-center gap-1`}>
289→                <MessageSquare size={18} className={style.color} />
290→                <span className={`text-[8px] font-bold ${style.color}`}>{name.slice(0, 3)}</span>
291→              </div>
292→            ))}
293→          </div>
294→          <h3 className="text-lg font-bold text-gray-300 mb-2">Simulateur de Citation</h3>
295→          <p className="text-sm text-gray-500 max-w-md">Posez une question et découvrez si ChatGPT, Claude, Perplexity, Gemini et AI Overviews mentionneraient votre marque dans leur réponse</p>
296→        </div>
297→      )}
298→    </div>
299→  );
300→};
301→
302→export default AiCitationSimulator;
