275→// Mini sparkline data generator for individual bot trend lines
276→const generateSparklineData = (crawlsWeek: number, trend: number) => {
277→  const points = 7;
278→  const data = [];
279→  const base = crawlsWeek / points;
280→  for (let i = 0; i < points; i++) {
281→    const trendFactor = trend >= 0
282→      ? 1 + (trend / 100) * (i / points)
283→      : 1 + (trend / 100) * (i / points);
284→    const noise = 0.7 + Math.random() * 0.6;
285→    data.push({
286→      day: `J${i + 1}`,
287→      crawls: Math.round(base * trendFactor * noise),
288→    });
289→  }
290→  return data;
291→};
